  1→//! Diagnostic probes for the first privilege-violation path during Amiga boot.
  2→//!
  3→//! These tests are ignored by default because they require local Kickstart ROMs
  4→//! and write JSON reports under `test_output/amiga/probes/`.
  5→
  6→mod common;
  7→
  8→use std::collections::VecDeque;
  9→use std::env;
 10→use std::fs;
 11→use std::path::PathBuf;
 12→
 13→use machine_amiga::{Amiga, AmigaChipset, AmigaConfig, AmigaModel, AmigaRegion};
 14→use serde::Serialize;
 15→
 16→use common::load_rom;
 17→
 18→const DEFAULT_MAX_TICKS: u64 = 120_000_000;
 19→const DEFAULT_FOLLOWUP_TICKS: u64 = 200_000;
 20→const FOLLOWUP_INSTRUCTION_LIMIT: usize = 32;
 21→
 22→struct ProbeSpec {
 23→    model: AmigaModel,
 24→    rom_path: &'static str,
 25→    report_name: &'static str,
 26→    slow_ram_size: usize,
 27→}
 28→
 29→#[derive(Serialize)]
 30→struct ProbeReport {
 31→    model: &'static str,
 32→    rom_path: &'static str,
 33→    max_ticks: u64,
 34→    followup_ticks: u64,
 35→    initial: CpuSnapshot,
 36→    vector8_before_boot: VectorSnapshot,
 37→    first_privilege_fault: Option<PrivilegeFault>,
 38→    final_state: CpuSnapshot,
 39→}
 40→
 41→#[derive(Serialize)]
 42→struct CpuSnapshot {
 43→    master_clock: u64,
 44→    overlay: bool,
 45→    pc: u32,
 46→    instr_start_pc: u32,
 47→    sr: u16,
 48→    usp: u32,
 49→    ssp: u32,
 50→    a7: u32,
 51→    ir: u16,
 52→    irc: u16,
 53→    d0: u32,
 54→    d1: u32,
 55→    a5: u32,
 56→    a6: u32,
 57→    exc_vector: Option<u8>,
 58→    followup_tag: u8,
 59→    halted: bool,
 60→    idle: bool,
 61→}
 62→
 63→#[derive(Serialize)]
 64→struct VectorSnapshot {
 65→    logical_vector8: u32,
 66→    physical_chip_vector8: u32,
 67→}
 68→
 69→#[derive(Serialize)]
 70→struct PrivilegeFault {
 71→    start_tick: u64,
 72→    handler_entry_tick: u64,
 73→    vector8_at_fault: VectorSnapshot,
 74→    leading_instructions: Vec<InstructionSnapshot>,
 75→    followup_instructions: Vec<InstructionSnapshot>,
 76→    start: CpuSnapshot,
 77→    handler: CpuSnapshot,
 78→    frame: StackFrameSnapshot,
 79→    a6_vector: ExecVectorSnapshot,
 80→    repeat_faults_within_followup: u32,
 81→    first_repeat: Option<RepeatFault>,
 82→}
 83→
 84→#[derive(Serialize)]
 85→struct StackFrameSnapshot {
 86→    stack_base: u32,
 87→    storage: &'static str,
 88→    saved_sr: u16,
 89→    saved_pc: u32,
 90→    format_word: Option<u16>,
 91→    vector_offset: Option<u16>,
 92→    saved_pc_words: Vec<u16>,
 93→    handler_words: Vec<u16>,
 94→}
 95→
 96→#[derive(Clone, Serialize)]
 97→struct InstructionSnapshot {
 98→    master_clock: u64,
 99→    instr_start_pc: u32,
100→    pc: u32,
101→    ir: u16,
102→    sr: u16,
103→    usp: u32,
104→    ssp: u32,
105→    a7: u32,
106→}
107→
108→#[derive(Serialize)]
109→struct RepeatFault {
110→    start_tick: u64,
111→    handler_entry_tick: Option<u64>,
112→    saved_pc: Option<u32>,
113→    saved_sr: Option<u16>,
114→}
115→
116→#[derive(Serialize)]
117→struct ExecVectorSnapshot {
118→    vector_addr: u32,
119→    words: Vec<u16>,
120→    abs_target: Option<u32>,
121→}
122→
123→fn max_ticks() -> u64 {
124→    let Some(raw) = env::var_os("AMIGA_PRIVILEGE_PROBE_TICKS") else {
125→        return DEFAULT_MAX_TICKS;
126→    };
127→
128→    raw.to_string_lossy()
129→        .trim()
130→        .parse()
131→        .expect("invalid AMIGA_PRIVILEGE_PROBE_TICKS value")
132→}
133→
134→fn followup_ticks() -> u64 {
135→    let Some(raw) = env::var_os("AMIGA_PRIVILEGE_PROBE_FOLLOWUP_TICKS") else {
136→        return DEFAULT_FOLLOWUP_TICKS;
137→    };
138→
139→    raw.to_string_lossy()
140→        .trim()
141→        .parse()
142→        .expect("invalid AMIGA_PRIVILEGE_PROBE_FOLLOWUP_TICKS value")
143→}
144→
145→fn chipset_for_model(model: AmigaModel) -> AmigaChipset {
146→    match model {
147→        AmigaModel::A1000 | AmigaModel::A500 | AmigaModel::A2000 => AmigaChipset::Ocs,
148→        AmigaModel::A500Plus | AmigaModel::A600 | AmigaModel::A3000 => AmigaChipset::Ecs,
149→        AmigaModel::A1200 | AmigaModel::A4000 => AmigaChipset::Aga,
150→    }
151→}
152→
153→fn model_name(model: AmigaModel) -> &'static str {
154→    match model {
155→        AmigaModel::A1000 => "a1000",
156→        AmigaModel::A500 => "a500",
157→        AmigaModel::A500Plus => "a500plus",
158→        AmigaModel::A600 => "a600",
159→        AmigaModel::A1200 => "a1200",
160→        AmigaModel::A2000 => "a2000",
161→        AmigaModel::A3000 => "a3000",
162→        AmigaModel::A4000 => "a4000",
163→    }
164→}
165→
166→fn output_path(report_name: &str) -> PathBuf {
167→    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
168→        .join("../../test_output/amiga/probes")
169→        .join(format!("{report_name}.json"))
170→}
171→
172→fn write_report(report_name: &str, report: &ProbeReport) {
173→    let path = output_path(report_name);
174→    if let Some(parent) = path.parent() {
175→        fs::create_dir_all(parent).expect("create probe output directory");
176→    }
177→    let data = serde_json::to_vec_pretty(report).expect("serialize probe report");
178→    fs::write(&path, data).expect("write probe report");
179→    println!("Privilege probe saved to {}", path.display());
180→}
181→
182→fn read_logical_byte(amiga: &Amiga, addr: u32) -> u8 {
183→    amiga.memory.read_byte(addr)
184→}
185→
186→fn read_logical_long(amiga: &Amiga, addr: u32) -> u32 {
187→    (u32::from(read_logical_byte(amiga, addr)) << 24)
188→        | (u32::from(read_logical_byte(amiga, addr.wrapping_add(1))) << 16)
189→        | (u32::from(read_logical_byte(amiga, addr.wrapping_add(2))) << 8)
190→        | u32::from(read_logical_byte(amiga, addr.wrapping_add(3)))
191→}
192→
193→fn physical_storage(amiga: &Amiga, addr: u32) -> &'static str {
194→    if !amiga.memory.fast_ram.is_empty() {
195→        let base = amiga.memory.fast_ram_base;
196→        let end = base.wrapping_add(amiga.memory.fast_ram.len() as u32);
197→        if addr >= base && addr < end {
198→            return "fast_ram";
199→        }
200→    }
201→
202→    let addr24 = addr & 0x00FF_FFFF;
203→    if addr24 < 0x20_0000 {
204→        "chip_ram"
205→    } else if (0xC0_0000..0xE0_0000).contains(&addr24) && !amiga.memory.slow_ram.is_empty() {
206→        "slow_ram"
207→    } else if addr24 >= 0xF8_0000 {
208→        "kickstart"
209→    } else {
210→        "unmapped"
211→    }
212→}
213→
214→fn read_physical_byte(amiga: &Amiga, addr: u32) -> u8 {
215→    if !amiga.memory.fast_ram.is_empty() {
216→        let base = amiga.memory.fast_ram_base;
217→        let end = base.wrapping_add(amiga.memory.fast_ram.len() as u32);
218→        if addr >= base && addr < end {
219→            let offset = (addr - base) & amiga.memory.fast_ram_mask;
220→            return amiga.memory.fast_ram[offset as usize];
221→        }
222→    }
223→
224→    let addr24 = addr & 0x00FF_FFFF;
225→    if addr24 < 0x20_0000 {
226→        return amiga.memory.chip_ram[(addr24 & amiga.memory.chip_ram_mask) as usize];
227→    }
228→    if (0xC0_0000..0xE0_0000).contains(&addr24) && !amiga.memory.slow_ram.is_empty() {
229→        let offset = (addr24 - 0xC0_0000) & amiga.memory.slow_ram_mask;
230→        return amiga.memory.slow_ram[offset as usize];
231→    }
232→    if addr24 >= 0xF8_0000 {
233→        return amiga.memory.kickstart[(addr24 & amiga.memory.kickstart_mask) as usize];
234→    }
235→    0
236→}
237→
238→fn read_physical_word(amiga: &Amiga, addr: u32) -> u16 {
239→    (u16::from(read_physical_byte(amiga, addr)) << 8)
240→        | u16::from(read_physical_byte(amiga, addr.wrapping_add(1)))
241→}
242→
243→fn read_physical_long(amiga: &Amiga, addr: u32) -> u32 {
244→    (u32::from(read_physical_word(amiga, addr)) << 16)
245→        | u32::from(read_physical_word(amiga, addr.wrapping_add(2)))
246→}
247→
248→fn read_words(amiga: &Amiga, addr: u32, count: usize) -> Vec<u16> {
249→    (0..count)
250→        .map(|i| read_physical_word(amiga, addr.wrapping_add((i as u32) * 2)))
251→        .collect()
252→}
253→
254→fn cpu_snapshot(amiga: &Amiga) -> CpuSnapshot {
255→    CpuSnapshot {
256→        master_clock: amiga.master_clock,
257→        overlay: amiga.memory.overlay,
258→        pc: amiga.cpu.regs.pc,
259→        instr_start_pc: amiga.cpu.instr_start_pc,
260→        sr: amiga.cpu.regs.sr,
261→        usp: amiga.cpu.regs.usp,
262→        ssp: amiga.cpu.regs.ssp,
263→        a7: amiga.cpu.regs.a(7),
264→        ir: amiga.cpu.ir,
265→        irc: amiga.cpu.irc,
266→        d0: amiga.cpu.regs.d[0],
267→        d1: amiga.cpu.regs.d[1],
268→        a5: amiga.cpu.regs.a(5),
269→        a6: amiga.cpu.regs.a(6),
270→        exc_vector: amiga.cpu.exc_vector,
271→        followup_tag: amiga.cpu.followup_tag,
272→        halted: amiga.cpu.is_halted(),
273→        idle: amiga.cpu.is_idle(),
274→    }
275→}
276→
277→fn vector8_snapshot(amiga: &Amiga) -> VectorSnapshot {
278→    VectorSnapshot {
279→        logical_vector8: read_logical_long(amiga, 0x20),
280→        physical_chip_vector8: read_physical_long(amiga, 0x20),
281→    }
282→}
283→
284→fn stack_frame_snapshot(amiga: &Amiga, handler_instr_start_pc: u32) -> StackFrameSnapshot {
285→    let stack_base = amiga.cpu.regs.ssp;
286→    let storage = physical_storage(amiga, stack_base);
287→    let saved_sr = read_physical_word(amiga, stack_base);
288→    let saved_pc = read_physical_long(amiga, stack_base.wrapping_add(2));
289→    let has_format_word = amiga.cpu.model.capabilities().movec;
290→    let format_word =
291→        has_format_word.then(|| read_physical_word(amiga, stack_base.wrapping_add(6)));
292→    let vector_offset = format_word.map(|word| word & 0x0FFF);
293→    let saved_pc_words = read_words(amiga, saved_pc, 4);
294→    let handler_words = read_words(amiga, handler_instr_start_pc, 4);
295→
296→    StackFrameSnapshot {
297→        stack_base,
298→        storage,
299→        saved_sr,
300→        saved_pc,
301→        format_word,
302→        vector_offset,
303→        saved_pc_words,
304→        handler_words,
305→    }
306→}
307→
308→fn instruction_snapshot(amiga: &Amiga) -> InstructionSnapshot {
309→    InstructionSnapshot {
310→        master_clock: amiga.master_clock,
311→        instr_start_pc: amiga.cpu.instr_start_pc,
312→        pc: amiga.cpu.regs.pc,
313→        ir: amiga.cpu.ir,
314→        sr: amiga.cpu.regs.sr,
315→        usp: amiga.cpu.regs.usp,
316→        ssp: amiga.cpu.regs.ssp,
317→        a7: amiga.cpu.regs.a(7),
318→    }
319→}
320→
321→fn exec_vector_snapshot(amiga: &Amiga) -> ExecVectorSnapshot {
322→    let vector_addr = amiga.cpu.regs.a(6).wrapping_sub(42);
323→    let words = read_words(amiga, vector_addr, 4);
324→    let abs_target = if words.len() >= 3 && words[0] == 0x4EF9 {
325→        Some((u32::from(words[1]) << 16) | u32::from(words[2]))
326→    } else {
327→        None
328→    };
329→    ExecVectorSnapshot {
330→        vector_addr,
331→        words,
332→        abs_target,
333→    }
334→}
335→
336→fn run_probe(spec: &ProbeSpec) {
337→    let Some(kickstart) = load_rom(spec.rom_path) else {
338→        return;
339→    };
340→
341→    let mut amiga = Amiga::new_with_config(AmigaConfig {
342→        model: spec.model,
343→        chipset: chipset_for_model(spec.model),
344→        region: AmigaRegion::Pal,
345→        kickstart,
346→        slow_ram_size: spec.slow_ram_size,
347→    });
348→
349→    let initial = cpu_snapshot(&amiga);
350→    let vector8_before_boot = vector8_snapshot(&amiga);
351→    let max_ticks = max_ticks();
352→    let followup_ticks = followup_ticks();
353→    let mut first_fault: Option<PrivilegeFault> = None;
354→    let mut pending_start: Option<(u64, CpuSnapshot, VectorSnapshot)> = None;
355→    let mut prev_exc_vector = amiga.cpu.exc_vector;
356→    let mut recent_instructions = VecDeque::with_capacity(16);
357→    let mut last_instr_start_pc = u32::MAX;
358→
359→    for tick in 0..max_ticks {
360→        amiga.tick();
361→
362→        if amiga.cpu.is_idle() && amiga.cpu.instr_start_pc != last_instr_start_pc {
363→            last_instr_start_pc = amiga.cpu.instr_start_pc;
364→            if recent_instructions.len() == 16 {
365→                recent_instructions.pop_front();
366→            }
367→            recent_instructions.push_back(instruction_snapshot(&amiga));
368→        }
369→
370→        if pending_start.is_none() && amiga.cpu.exc_vector == Some(8) {
371→            let start = cpu_snapshot(&amiga);
372→            let vectors = vector8_snapshot(&amiga);
373→            println!(
374→                "[{}] first privilege-violation sequence started at tick {}: pc=${:08X} ipc=${:08X} sr=${:04X} ssp=${:08X} usp=${:08X}",
375→                model_name(spec.model),
376→                amiga.master_clock,
377→                start.pc,
378→                start.instr_start_pc,
379→                start.sr,
380→                start.ssp,
381→                start.usp,
382→            );
383→            pending_start = Some((tick, start, vectors));
384→        } else if let Some((start_tick, start, vectors)) = pending_start.take() {
385→            if prev_exc_vector == Some(8) && amiga.cpu.exc_vector.is_none() {
386→                let handler = cpu_snapshot(&amiga);
387→                let frame = stack_frame_snapshot(&amiga, handler.instr_start_pc);
