  2→import Layout from '../../layouts/Layout.astro';
  3→import { Terminal, Monitor, Download, CheckCircle, Cpu, Package, Camera, Code } from '@lucide/astro';
  4→import { getActivePlatforms } from '../../lib/platforms';
  5→
  6→const platformsData = await getActivePlatforms();
  7→
  8→// Transform to the shape needed by this page
  9→const platforms = platformsData.map(p => ({
 10→  name: p.data.shortName,
 11→  fullName: p.data.name,
 12→  slug: p.id,
 13→  image: p.data.dockerImage,
 14→  color: p.data.color,
 15→  assembler: p.data.assembler,
 16→  emulator: p.data.emulator,
 17→  buildOutput: p.data.buildOutput,
 18→  extras: p.data.toolchainExtras,
 19→}));
