 52→
 53→    <!-- Quick Start -->
 54→    <section class="quick-start">
 55→      <div class="container">
 56→        <h2>Quick Start</h2>
 57→        <div class="steps">
 58→          <div class="step">
 59→            <div class="step-number">1</div>
 60→            <div class="step-content">
 61→              <h3>Install Docker Desktop</h3>
 62→              <p>Free from <a href="https://www.docker.com/products/docker-desktop/" target="_blank" rel="noopener">docker.com</a> for Mac, Windows, and Linux</p>
 63→            </div>
 64→          </div>
 65→          <div class="step">
 66→            <div class="step-number">2</div>
 67→            <div class="step-content">
 68→              <h3>Download the Toolchain</h3>
 69→              <div class="code-block">
 70→                <code>docker pull ghcr.io/code198x/commodore-64</code>
 71→              </div>
 72→            </div>
 73→          </div>
 74→          <div class="step">
 75→            <div class="step-number">3</div>
 76→            <div class="step-content">
 77→              <h3>Build Your Code</h3>
 78→              <div class="code-block">
 79→                <code>docker run -v ./code:/code ghcr.io/code198x/commodore-64 acme game.asm -o game.prg</code>
 80→              </div>
 81→            </div>
 82→          </div>
 83→        </div>
